import{_ as t,o as a,c as r,ag as n}from"./chunks/framework.eQLvDOR_.js";const m=JSON.parse('{"title":"agent-teams-pattern","description":"","frontmatter":{"title":"agent-teams-pattern","concept":"团队模式","concept_id":"agent-teams-pattern","aliases":["Agent Teams"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md"],"related_concepts":["[[multi-agent-orchestrator]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/agent-teams-pattern.md","filePath":"wiki/concepts/agent-teams-pattern.md","lastUpdated":null}'),i={name:"wiki/concepts/agent-teams-pattern.md"};function o(s,e,c,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="团队模式-agent-teams" tabindex="-1">团队模式 (Agent Teams) <a class="header-anchor" href="#团队模式-agent-teams" aria-label="Permalink to &quot;团队模式 (Agent Teams)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>相较于随时创建与销毁的 Sub-Agent，此模式下涉及一组具备持久状态的长生命周期 Agent。它们独立运作，基于公共的 backlog 或者相互传递复杂消息体进行常态化协作。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>跨周期的持久记忆</strong>：各个团队成员 Agent 能在不同会话中积累处理任务的情境记忆（如总结历史漏洞和风格）。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md</a>）</li><li><strong>排队与缓冲设计</strong>：为了让各个成员异步合作，系统中通常要利用工作队列。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>对于需要“背景知识发酵”和“主观能动性”长期运营（如内容创作流：Researcher &amp; Writer 互相异步批阅素材），应使用 Agent 团队模式，并赋予它们各自管理内部上下文的持久化状态库。而针对即用即抛的代码生成，Orchestrator 更佳。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/multi-agent-orchestrator.html">multi-agent-orchestrator</a> — 作为应对不同复杂环境的镜像解决方案。</li></ul>',9)])])}const u=t(i,[["render",o]]);export{m as __pageData,u as default};
